+fn offset_void_or_none(base: *const u8, ret: *const c_void) -> Option<isize> {
+    if ret.is_null() {
+        None
+    } else {
+        // SAFETY: every caller compares return pointers from byte-search
+        // functions against the same allocation passed as that function's
